import React, { useEffect, useState } from "react";
import { Card, CardContent, TextField, Button, MenuItem } from "@mui/material";
import { useNavigate, useParams } from "react-router-dom";
import axios from "axios";

const EditDrug = () => {
    const { id } = useParams();
    const navigate = useNavigate();
    const [drug, setDrug] = useState({
        code: "",
        name: "",
        type: "",
        price: "",
        unit: "",
        description: ""
    });
    const [types, setTypes] = useState([]);

    useEffect(() => {
        axios.get(`/api/drugs/${id}`).then((response) => {
            setDrug(response.data);
        });
        axios.get("/api/drug-types").then((response) => {
            setTypes(response.data);
        });
    }, [id]);

    const handleChange = (e) => {
        setDrug({ ...drug, [e.target.name]: e.target.value });
    };

    const handleSubmit = (e) => {
        e.preventDefault();
        axios.put(`/api/drugs/${id}`, drug).then(() => {
            navigate("/drugs");
        });
    };

    return (
        <Card>
            <CardContent>
                <h2>Chỉnh sửa thuốc</h2>
                <form onSubmit={handleSubmit}>
                    <TextField
                        fullWidth
                        label="Mã thuốc"
                        name="code"
                        value={drug.code}
                        onChange={handleChange}
                        margin="normal"
                        required
                    />
                    <TextField
                        fullWidth
                        label="Tên thuốc"
                        name="name"
                        value={drug.name}
                        onChange={handleChange}
                        margin="normal"
                        required
                    />
                    <TextField
                        select
                        fullWidth
                        label="Loại thuốc"
                        name="type"
                        value={drug.type}
                        onChange={handleChange}
                        margin="normal"
                        required
                    >
                        {types.map((type) => (
                            <MenuItem key={type.id} value={type.id}>{type.name}</MenuItem>
                        ))}
                    </TextField>
                    <TextField
                        fullWidth
                        label="Giá"
                        name="price"
                        type="number"
                        value={drug.price}
                        onChange={handleChange}
                        margin="normal"
                        required
                    />
                    <TextField
                        fullWidth
                        label="Đơn vị tính"
                        name="unit"
                        value={drug.unit}
                        onChange={handleChange}
                        margin="normal"
                        required
                    />
                    <TextField
                        fullWidth
                        label="Mô tả"
                        name="description"
                        value={drug.description}
                        onChange={handleChange}
                        margin="normal"
                        multiline
                        rows={3}
                    />
                    <Button type="submit" variant="contained" color="primary">Lưu lại</Button>
                    <Button onClick={() => navigate("/drugs")} variant="outlined" color="secondary" style={{ marginLeft: "10px" }}>Quay lại</Button>
                </form>
            </CardContent>
        </Card>
    );
};

export default EditDrug;
